/**
 * Analytics
 *
 * NO-OP analytics implementation.
 *
 * This project intentionally does not write analytics events.
 * We keep this class so viewer code can call `analytics.track(...)` without
 * needing to change all call sites.
 */

export class Analytics {
  /**
   * @param {object} opts
   * @param {string} [opts.projectId] Panorama360 project UUID (from your `projects` table)
   */
  constructor({ projectId } = {}) {
    void projectId;
  }

  async track(event, payload = {}) {
    void event;
    void payload;
    return;
  }
}


